"""Базовый класс фильтров + провенанс + reflect-паддинг."""from __future__ import annotationsfrom typing import Anyimport numpy as npfrom ..core.interfaces import IFilterfrom ..core.types import Signal_ALLOWED_TYPES = {"int", "float", "bool", "enum"}def _check_schema(schema: dict[str, dict[str, Any]]) -> None:    if not isinstance(schema, dict) or not schema:        raise ValueError("params_schema must be a non-empty dict")    for key, spec in schema.items():        if not isinstance(spec, dict):            raise ValueError(f"Param '{key}': spec must be dict")        t = spec.get("type")        if t not in _ALLOWED_TYPES:            raise ValueError(f"Param '{key}': bad 'type' ({t!r})")        if "default" not in spec:            raise ValueError(f"Param '{key}': missing 'default'")        if "label" not in spec or not isinstance(spec["label"], str):            raise ValueError(f"Param '{key}': missing string 'label'")        if t in ("int", "float"):            if "min" not in spec or "max" not in spec:                raise ValueError(f"Param '{key}': numeric requires min/max")            if spec["max"] <= spec["min"]:                raise ValueError(f"Param '{key}': max must be > min")            if not (spec["min"] <= spec["default"] <= spec["max"]):                raise ValueError(f"Param '{key}': default out of [min, max]")        if t == "enum":            choices = spec.get("choices")            if not isinstance(choices, (list, tuple)) or not choices:                raise ValueError(f"Param '{key}': enum requires non-empty 'choices'")            if spec["default"] not in choices:                raise ValueError(f"Param '{key}': default not in choices")def _fill_and_validate(params: dict[str, Any],                       schema: dict[str, dict[str, Any]]) -> dict[str, Any]:    extras = set(params) - set(schema)    if extras:        raise ValueError(f"Unknown params: {sorted(extras)}")    out: dict[str, Any] = {}    for key, spec in schema.items():        raw = params.get(key, spec["default"])        t = spec["type"]        try:            if t == "int":                val: Any = int(raw)            elif t == "float":                val = float(raw)            elif t == "bool":                val = bool(raw)            else:                val = str(raw)        except (TypeError, ValueError) as e:            raise ValueError(f"Param '{key}': cannot cast {raw!r} to {t} ({e})") from e        if t in ("int", "float") and not (spec["min"] <= val <= spec["max"]):            raise ValueError(                f"Param '{key}'={val} out of [{spec['min']}, {spec['max']}]"            )        if t == "enum" and val not in spec["choices"]:            raise ValueError(f"Param '{key}'={val!r} not in {spec['choices']}")        out[key] = val    return outdef _validate_input_signal(signal: Signal) -> None:    if not isinstance(signal, Signal):        raise TypeError("expected Signal instance")    if signal.x.size == 0:        raise ValueError("input signal is empty")    if signal.t.size != signal.x.size:        raise ValueError("len(t) != len(x) in input signal")    if not np.all(np.isfinite(signal.x)):        raise ValueError("input signal contains NaN/Inf")    if signal.fs <= 0:        raise ValueError("input signal has non-positive fs")def _check_odd_window(name: str, w: int, n_samples: int) -> None:    if w <= 0 or (w % 2) == 0:        raise ValueError(f"{name}={w} должно быть положительным нечётным целым")    if w > n_samples:        raise ValueError(f"{name}={w} больше длины сигнала N={n_samples}")def _reflect_pad(x: np.ndarray, pad: int) -> np.ndarray:    if pad == 0:        return x    return np.pad(x, pad, mode="reflect")class BaseFilter(IFilter):    def __init_subclass__(cls, **kwargs: Any) -> None:        super().__init_subclass__(**kwargs)        schema = getattr(cls, "params_schema", None)        if schema is not None:            _check_schema(schema)        name = getattr(cls, "name", None)        if not isinstance(name, str) or not name.strip():            raise ValueError(f"{cls.__name__}: 'name' must be a non-empty string")        desc = getattr(cls, "description", None)        if not isinstance(desc, str) or not desc:            raise ValueError(f"{cls.__name__}: 'description' must be a non-empty string")    def apply(self, noisy: Signal, **params: Any) -> Signal:        _validate_input_signal(noisy)        p = _fill_and_validate(params, self.params_schema)        x = noisy.x.astype(np.float64, copy=False)        y = self._filter(x, p, noisy)        y = np.asarray(y, dtype=np.float64)        if y.shape != x.shape:            raise ValueError(                f"{self.name}: output shape {y.shape} != input {x.shape}"            )        if not np.all(np.isfinite(y)):            raise ValueError(f"{self.name}: output contains NaN/Inf")        out_params: dict[str, Any] = {"filter_name": self.name}        out_params.update(p)        out_params["upstream"] = dict(noisy.params)        return Signal(            t=noisy.t.copy(), x=y, fs=noisy.fs,            name=noisy.name, params=out_params,        )    def _filter(self, x: np.ndarray, p: dict[str, Any],                signal: Signal) -> np.ndarray:        raise NotImplementedError